const { ApolloServer, gql, PubSub } = require('apollo-server');
const http = require('http');
const WebSocket = require('ws');

const pubsub = new PubSub();
const MESSAGE_ADDED = 'MESSAGE_ADDED';

const typeDefs = gql`
  type Message {
    id: ID!
    content: String!
    roomId: ID!
  }

  type Query {
    messages(roomId: ID!): [Message]
  }

  type Subscription {
    messageAdded(roomId: ID!): Message
  }

  type Mutation {
    addMessage(roomId: ID!, content: String!): Message
  }
`;

const messages = [];

const resolvers = {
  Query: {
    messages: (parent, { roomId }) => messages.filter(message => message.roomId === roomId),
  },
  Mutation: {
    addMessage: (parent, { roomId, content }) => {
      const message = { id: messages.length + 1, content, roomId };
      messages.push(message);
      pubsub.publish(MESSAGE_ADDED, { messageAdded: message, roomId });
      return message;
    },
  },
  Subscription: {
    messageAdded: {
      subscribe: (parent, { roomId }) => {
        return pubsub.asyncIterator([MESSAGE_ADDED]);
      },
    },
  },
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    // Implement any authentication or context setup here
    return {};
  },
});

const httpServer = http.createServer(server);
const wsServer = new WebSocket.Server({ server: httpServer });

server.installSubscriptionHandlers(wsServer);

httpServer.listen({ port: 4000 }, () => {
  console.log('Server is running on http://localhost:4000/graphql');
});